package org.example;

import java.math.BigDecimal;

public abstract class Cuenta {
    // Atributos privados
    private String id;
    private String titular;
    private BigDecimal saldo;


    // Constructor
    public Cuenta(String id, String titular, BigDecimal saldo) {
        this.id = id;
        this.titular = titular;
        this.saldo = saldo;
    }

    public String getId() {
        return id;
    }

    public void setId(String id) {
        this.id = id;
    }

    public String getTitular() {
        return titular;
    }

    public void setTitular(String titular) {
        this.titular = titular;
    }

    public BigDecimal getSaldo() {
        return saldo;
    }

    public void setSaldo(BigDecimal saldo) {
        this.saldo = saldo;
    }

    //METODOS
    public abstract void depositar(BigDecimal monto);
    public abstract void retirar(BigDecimal monto);

    public void transferir(Cuenta cuentaDestino, BigDecimal monto) throws MontoInvalidoException, SaldoInsuficienteException {
        System.out.println("Transfiriendo " + monto + " de " + getTitular() + " a " + cuentaDestino.getTitular());

        if (monto.compareTo(BigDecimal.ZERO) <= 0) {
            throw new MontoInvalidoException("Monto invalido para transferir: " + monto);
        }

        if (getSaldo().compareTo(monto) < 0) {
            throw new SaldoInsuficienteException("Saldo insuficiente para transferir " + monto);
        }

        this.retirar(monto);
        cuentaDestino.depositar(monto);

        System.out.println("Transferencia exitosamente");
    }
}

package org.example;

import java.math.BigDecimal;

public class CuentaCorriente extends Cuenta{
    public CuentaCorriente(String id, String titular, java.math.BigDecimal saldo) {
        super(id, titular, saldo);
    }

    @Override
    public void depositar(java.math.BigDecimal monto) {
        System.out.println ("Depositando " + monto + " en la cuenta de corriente de " + getTitular());
    }
    @Override
    public void retirar(java.math.BigDecimal monto) {
        System.out.println ("Retirando " + monto + " de la cuenta de corriente de " + getTitular());
    }
}

package org.example;

import java.math.BigDecimal;

public class CuentaCorriente extends Cuenta{
    public CuentaCorriente(String id, String titular, BigDecimal saldo) {
        super(id, titular, saldo);
    }

    @Override
    public void depositar(BigDecimal monto) {
        if (monto.compareTo(BigDecimal.ZERO) <= 0) {
            throw new MontoInvalidoException("Monto invalido para depositar: " + monto);
        }
        System.out.println("Depositando " + monto + " en la cuenta de corriente de " + getTitular());
        setSaldo(getSaldo().add(monto));
    }
    @Override
    public void retirar(BigDecimal monto) {
        if (monto.compareTo(BigDecimal.ZERO) <= 0) {
            throw new MontoInvalidoException("Monto invalido para retirar: " + monto);
        }
        System.out.println("Retirando " + monto + " de la cuenta de corriente de " + getTitular());
        if (getSaldo().compareTo(monto) >= 0) {
            setSaldo(getSaldo().subtract(monto));
            System.out.println("Retiro exitoso de " + monto);
        } else {
            throw new SaldoInsuficienteException("Saldo insuficiente para retirar " + monto);
        }
    }
}

package org.example;

public class MontoInvalidoException extends Exception {
    public MontoInvalidoException(String message) {
        super(message);
    }
}
